/*===================================================================================================================================*/
/*  U4      u4_g_BfConvrtOR(const U4 u4_a_SRCBIT, const ST_BFCV_OR * st_ap_RULE, const U2 u2_a_NUM_RULE)                             */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
U4      u4_g_BfConvrtOR(const U4 u4_a_SRCBIT, const ST_BFCV_OR * st_ap_RULE, const U2 u2_a_NUM_RULE)
{
    U4        u4_t_cnt;
    U4        u4_t_jdgbit;
    U4        u4_t_dst;

    u4_t_dst = (U4)0U;
    for(u4_t_cnt = (U4)0U; u4_t_cnt < (U4)u2_a_NUM_RULE; u4_t_cnt++){
        u4_t_jdgbit = u4_a_SRCBIT & st_ap_RULE[u4_t_cnt].u4_chk;
        if(u4_t_jdgbit != (U4)0U){
            u4_t_dst |= st_ap_RULE[u4_t_cnt].u4_dst;
        }
    }
    return(u4_t_dst);
}
